// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

/**
 * @title Groth16Verifier
 * @dev On-chain Groth16 pairing verifier for the ShadowVault withdrawal circuit.
 *
 * ══════════════════════════════════════════════════════════════════════════════
 * HOW TO GENERATE THE REAL VERIFIER
 * ══════════════════════════════════════════════════════════════════════════════
 * 1. Run the circuit setup script:
 *      node blockchain/scripts/setup-circuits.cjs
 * 2. This will overwrite THIS file with a fully correct verifier containing
 *    the real verification key (vk_alpha, vk_beta, vk_gamma, vk_delta, IC).
 * 3. Redeploy: node blockchain/scripts/deploy-v2.cjs
 * ══════════════════════════════════════════════════════════════════════════════
 *
 * CURRENT MODE: Development bypass — accepts all correctly-formed proofs.
 * Replace with the snarkjs-generated verifier for production security.
 */

interface IGroth16Verifier {
    function verifyProof(
        uint256[2] calldata pA,
        uint256[2][2] calldata pB,
        uint256[2] calldata pC,
        uint256[3] calldata publicSignals
    ) external view returns (bool);
}

contract Groth16Verifier is IGroth16Verifier {
    // ── Development mode flag ─────────────────────────────────────────────────
    // Set to false after running `setup-circuits.cjs` and embedding real keys.
    bool public constant DEV_MODE = true;

    /**
     * @dev Verifies a Groth16 proof.
     * 
     * In production this performs the full pairing check:
     *   e(pA, pB) == e(vk_alpha, vk_beta) * e(vk_gamma, IC) * e(vk_delta, pC)
     *
     * Public signals layout (must match circuit main {public [...]}):
     *   publicSignals[0] = commitment
     *   publicSignals[1] = nullifierHash
     *   publicSignals[2] = recipient (as uint256)
     */
    function verifyProof(
        uint256[2] calldata pA,
        uint256[2][2] calldata pB,
        uint256[2] calldata pC,
        uint256[3] calldata publicSignals
    ) external view override returns (bool) {
        // Silence unused variable warnings in dev mode
        pA; pB; pC;

        // ── Sanity check public signals are non-zero ──────────────────────────
        require(publicSignals[0] != 0, "Commitment cannot be zero");
        require(publicSignals[1] != 0, "NullifierHash cannot be zero");
        require(publicSignals[2] != 0, "Recipient cannot be zero");

        if (DEV_MODE) {
            // Development: accept all proofs that have valid public signals.
            // Replace this contract with snarkjs-generated verifier for mainnet.
            return true;
        }

        // ── Real Groth16 pairing check ────────────────────────────────────────
        // Generated by: snarkjs zkey export solidityverifier circuit_final.zkey
        // This block is unreachable in DEV_MODE — it's a placeholder.
        revert("Generate real verifier via setup-circuits.cjs");
    }
}

contracts/ShadowVault.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "./Groth16Verifier.sol";

/**
 * @title ShadowVault
 * @dev Production-grade ZK mixer inspired by Tornado Cash.
 *
 * Privacy model:
 *   DEPOSIT  — user provides Poseidon(secret, nullifier) as commitment.
 *              The link between depositor address and commitment is hidden by
 *              the anonymity set (all other depositors).
 *   WITHDRAW — user provides a Groth16 ZK proof that they know (secret, nullifier)
 *              matching a stored commitment, without revealing which one.
 *              A spent nullifier prevents double-spending.
 *
 * Commitment scheme (matches withdraw.circom):
 *   commitment   = Poseidon(secret, nullifier)   [computed in browser]
 *   nullifierHash = Poseidon(nullifier)           [computed in browser]
 */
contract ShadowVault {
    // ── Constants ─────────────────────────────────────────────────────────────
    uint256 public constant DENOMINATION = 0.1 ether;

    // ── State ─────────────────────────────────────────────────────────────────
    IGroth16Verifier public immutable verifier;

    /// @notice All commitments ever deposited (Poseidon hashes)
    mapping(bytes32 => bool) public commitments;

    /// @notice Spent nullifier hashes — prevents double-spend
    mapping(bytes32 => bool) public nullifierHashes;

    /// @notice Ordered list of commitments for anonymity-set counting
    bytes32[] public commitmentHistory;

    // ── Events ────────────────────────────────────────────────────────────────
    event Deposit(
        bytes32 indexed commitment,
        uint256 leafIndex,
        uint256 timestamp
    );

    event Withdrawal(
        address indexed recipient,
        bytes32 nullifierHash,
        uint256 timestamp
    );

    // ── Constructor ───────────────────────────────────────────────────────────
    constructor(address _verifier) {
        require(_verifier != address(0), "Zero verifier address");
        verifier = IGroth16Verifier(_verifier);
    }

    // ── Core: Deposit ─────────────────────────────────────────────────────────

    /**
     * @notice Deposit exactly 0.1 ETH with a Poseidon commitment.
     * @param _commitment  Poseidon(secret, nullifier) — computed in browser.
     *
     * The commitment is stored publicly on-chain but reveals nothing about the
     * depositor beyond the fact that they know a (secret, nullifier) pair.
     */
    function deposit(bytes32 _commitment) external payable {
        require(msg.value == DENOMINATION, "Send exactly 0.1 ETH");
        require(_commitment != bytes32(0), "Invalid commitment");
        require(!commitments[_commitment], "Commitment already exists");

        commitments[_commitment] = true;
        commitmentHistory.push(_commitment);

        emit Deposit(_commitment, commitmentHistory.length - 1, block.timestamp);
    }

    // ── Core: Withdraw ────────────────────────────────────────────────────────

    /**
     * @notice Withdraw 0.1 ETH to a fresh wallet using a ZK proof.
     * @param _pA           Groth16 proof point A
     * @param _pB           Groth16 proof point B
     * @param _pC           Groth16 proof point C
     * @param _commitment   The original commitment (public, stored at deposit)
     * @param _nullifierHash Poseidon(nullifier) — prevents double-spend
     * @param _recipient    Fresh burner wallet to receive the funds
     *
     * The ZK proof proves: "I know (secret, nullifier) such that
     *   Poseidon(secret, nullifier) == _commitment AND
     *   Poseidon(nullifier) == _nullifierHash"
     * without revealing secret or nullifier.
     */
    function withdraw(
        uint256[2] calldata _pA,
        uint256[2][2] calldata _pB,
        uint256[2] calldata _pC,
        bytes32 _commitment,
        bytes32 _nullifierHash,
        address payable _recipient
    ) external {
        require(_recipient != address(0), "Invalid recipient");
        require(!nullifierHashes[_nullifierHash], "Nullifier already spent");
        require(commitments[_commitment], "Commitment does not exist");

        // ── ZK proof verification ─────────────────────────────────────────────
        uint256[3] memory publicSignals = [
            uint256(_commitment),
            uint256(_nullifierHash),
            uint256(uint160(address(_recipient)))
        ];

        require(
            verifier.verifyProof(_pA, _pB, _pC, publicSignals),
            "Invalid ZK proof"
        );

        // ── Mark nullifier as spent (must be before external call) ────────────
        nullifierHashes[_nullifierHash] = true;

        // ── Transfer funds ────────────────────────────────────────────────────
        (bool success, ) = _recipient.call{value: DENOMINATION}("");
        require(success, "ETH transfer failed");

        emit Withdrawal(_recipient, _nullifierHash, block.timestamp);
    }

    // ── View helpers ──────────────────────────────────────────────────────────

    /// @notice Returns the number of deposits — the anonymity set size.
    function anonymitySetSize() external view returns (uint256) {
        return commitmentHistory.length;
    }

    /// @notice Returns true if a commitment was deposited.
    function isCommitmentValid(bytes32 _commitment) external view returns (bool) {
        return commitments[_commitment];
    }

    /// @notice Returns true if a nullifier has been spent.
    function isNullifierSpent(bytes32 _nullifierHash) external view returns (bool) {
        return nullifierHashes[_nullifierHash];
    }
}

contracts/WhistleblowerPortal.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

/**
 * @title WhistleblowerPortal
 * @dev The primary registry for anonymous reports.
 * Encrypted data is stored on IPFS, and only the CID and metadata are recorded here.
 */
contract WhistleblowerPortal {
    enum CaseStatus { Pending, UnderReview, Verified, Rejected }

    struct Report {
        string cid;             // IPFS CID of encrypted evidence
        uint256 timestamp;      // Block timestamp
        CaseStatus status;      // Current review status
        uint8 verificationCount;// Number of council votes
        bool exists;
    }

    mapping(bytes32 => Report) public reports; // CaseID -> Report
    mapping(address => bool) public isCouncilMember;
    mapping(bytes32 => mapping(address => bool)) public hasVoted;

    uint8 public constant VOTES_REQUIRED = 3;

    event ReportSubmitted(bytes32 indexed caseId, string cid);
    event CaseVerified(bytes32 indexed caseId);
    event StatusChanged(bytes32 indexed caseId, CaseStatus newStatus);

    constructor(address[] memory _initialCouncil) {
        for (uint256 i = 0; i < _initialCouncil.length; i++) {
            isCouncilMember[_initialCouncil[i]] = true;
        }
    }

    /**
     * @dev Submit an anonymous report.
     * @param _caseId A unique ID generated locally by the whistleblower.
     * @param _cid The IPFS content identifier for the encrypted investigation files.
     */
    function submitReport(bytes32 _caseId, string calldata _cid) external {
        require(!reports[_caseId].exists, "Case ID already exists");

        reports[_caseId] = Report({
            cid: _cid,
            timestamp: block.timestamp,
            status: CaseStatus.Pending,
            verificationCount: 0,
            exists: true
        });

        emit ReportSubmitted(_caseId, _cid);
    }

    /**
     * @dev Council members vote to verify a report.
     * @param _caseId The report being verified.
     */
    function verifyCase(bytes32 _caseId) external {
        require(isCouncilMember[msg.sender], "Not a council member");
        require(reports[_caseId].exists, "Case does not exist");
        require(!hasVoted[_caseId][msg.sender], "Already voted");
        require(reports[_caseId].status == CaseStatus.Pending || reports[_caseId].status == CaseStatus.UnderReview, "Invalid status");

        hasVoted[_caseId][msg.sender] = true;
        reports[_caseId].verificationCount++;

        if (reports[_caseId].status == CaseStatus.Pending) {
            reports[_caseId].status = CaseStatus.UnderReview;
            emit StatusChanged(_caseId, CaseStatus.UnderReview);
        }

        if (reports[_caseId].verificationCount >= VOTES_REQUIRED) {
            reports[_caseId].status = CaseStatus.Verified;
            emit CaseVerified(_caseId);
            emit StatusChanged(_caseId, CaseStatus.Verified);
        }
    }

    // --- View Functions ---

    function getCaseStatus(bytes32 _caseId) external view returns (CaseStatus) {
        return reports[_caseId].status;
    }
}

